        Optional<ExtensionContext> current = context.getParent();

        while(current.isPresent()) {
            ExtensionContext ctx = current.get();
            Optional<Object> testInstance = ctx.getTestInstance()
            if (testInstance.isPresent()) { // will never be true
                // do something with testInstance
            }
            current = ctx.getParent();
        }
```

